type WildPokemonProtoList struct{ l protoreflect.List }

func (l WildPokemonProtoList) Len() int {
	if l.l == nil {
		return 0
	}
	return l.l.Len()
}

func (l WildPokemonProtoList) At(i int) WildPokemonProto {
	return WildPokemonProto{l.l.Get(i).Message()}
}

func (l WildPokemonProtoList) All() iter.Seq[WildPokemonProto] {
	return func(yield func(WildPokemonProto) bool) {
		if l.l == nil {
			return
		}
		for i, n := 0, l.l.Len(); i < n; i++ {
			if !yield(WildPokemonProto{l.l.Get(i).Message()}) {
				return
			}
		}
	}
}

